import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    best_node = None
    min_score = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        travel_time = distance / truck_speed

        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[idx]
        wait_time = max(0, start_time - arrival_time)

        if arrival_time > end_time:
            penalty = float('inf')  # Large penalty if cannot meet time window
        else:
            penalty = (end_time - arrival_time) ** 2  # Quadratic penalty to prioritize earlier arrivals

        distance_to_others = np.mean([euclidean_distance(customer_pos, pos) for pos in unvisited_customers])
        truck_proximity_penalty = np.mean([euclidean_distance(customer_pos, truck_pos) for truck_pos in all_truck_pos])

        score = travel_time + wait_time + penalty - 0.5 * distance_to_others + 0.5 * truck_proximity_penalty

        if score < min_score:
            min_score = score
            best_node = idx

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(pos1 - pos2) / speed

    penalties = []
    for i, customer in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        start_time, end_time = time_windows[i]

        if arrival_time < start_time:
            waiting_time = start_time - arrival_time
        else:
            waiting_time = 0

        if arrival_time > end_time:
            penalty = float('inf')  
        else:
            penalty = end_time - arrival_time

        total_cost = travel_time + waiting_time + penalty
        penalties.append((i, total_cost))

    if penalties:
        penalties.sort(key=lambda x: x[1])
        best_node = penalties[0][0]
    else:
        best_node = None  

    return best_node
